Rule.Source:
  import java.sql.Connection;
  import java.sql.Statement;
  import java.sql.PreparedStatement;
  import java.sql.DriverManager;
  import java.sql.ResultSet;
  import java.sql.SQLException;
  import sailpoint.tools.Util;

  import sailpoint.object.Application;


  String SOURCE_DB_DRIVER = null;  
  String SOURCE_JDBC_URL = null;
  String SOURCE_USERNAME = null;
  String SOURCE_PASSWORD = null;

  Application peopleSoftApp = context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Primary");
  if (peopleSoftApp != null) {

    SOURCE_DB_DRIVER = peopleSoftApp.getAttributeValue("driverClass");  
    SOURCE_JDBC_URL = peopleSoftApp.getAttributeValue("url"); 
    SOURCE_USERNAME = peopleSoftApp.getAttributeValue("user"); 
    SOURCE_PASSWORD = peopleSoftApp.getAttributeValue("password"); 
  }
  if (peopleSoftApp != null) {
	context.decache(peopleSoftApp);
  }

  Connection sourceConnection = null;
  Connection destConnection = null;
  Map sourceTables = null;
  Map destTables = null;
  try{
    //Reading from source tables
    Class.forName(SOURCE_DB_DRIVER);
    sourceConnection = DriverManager.getConnection(SOURCE_JDBC_URL,SOURCE_USERNAME,context.decrypt(SOURCE_PASSWORD));
    if (sourceConnection != null) {
      sourceTables = getDetailsFromDatabase(sourceConnection);
      sourceConnection.close();
    }
   

    //Reading from target tables
    destConnection = context.getJdbcConnection();
    if (destConnection != null) {
      destTables = getDetailsFromDatabase(destConnection);
    
      //Updating Job Titles
      List sourceJobsList = sourceTables.get(JOB_CODE_TABLE);
      List destJobsList = destTables.get(JOB_CODE_TABLE);
      sourceJobsList.removeAll(destJobsList);
      insertIntoDB(destConnection, sourceJobsList, JOB_CODE_TABLE);

      //Updating Departments
      List sourceDeptList = sourceTables.get(DEPT_TABLE);
      List destDeptList = destTables.get(DEPT_TABLE);
      sourceDeptList.removeAll(destDeptList);
      insertIntoDB(destConnection, sourceDeptList, DEPT_TABLE);

      //Updating Locations
      List sourceLocationList = sourceTables.get(LOCATION_TABLE);
      List destLocationList = destTables.get(LOCATION_TABLE);
      sourceLocationList.removeAll(destLocationList);
      insertIntoDB(destConnection, sourceLocationList, LOCATION_TABLE);

      destConnection.close();
    }
  }catch(SQLException se){
    log.error("Exception in processing database fields: "+se.getMessage());
  }catch(Exception e){
    log.error("Exception in processing database fields: "+e.getMessage());
  }finally{
    try{
      if(sourceConnection!=null)
        sourceConnection.close();
      if(destConnection!=null)
        destConnection.close();

    }catch(SQLException se2){
      log.error("Exception in closing database connections: "+se2.getMessage());
    }
  }

  return "done";
